                    std::string response_data = target.ip + ":" + std::to_string(target.port);

                    SendSecurePacket(sock, ip, port, PT_INTRO_RESPONSE, 
                                    response_data.c_str(), response_data.size());
                    std::cout << "[PEER] Introduced " << ip << " to " << target.ip << std::endl;
                }
